import React from "react";

const days = ["MON", "TUE", "WED", "THU", "FRI", "SAT", "SUN"];

// Mock data based on the image: heights in pixels or percentage
const data = [
  { family: 40, unknown: 25 }, // MON
  { family: 30, unknown: 15 }, // TUE
  { family: 35, unknown: 45 }, // WED
  { family: 60, unknown: 10 }, // THU
  { family: 20, unknown: 55 }, // FRI
  { family: 35, unknown: 25 }, // SAT
  { family: 45, unknown: 10 }, // SUN
];

export default function FaceDetectionChart() {
  return (
    <div
      className="flex flex-col gap-8 p-6 md:p-8 rounded-xl w-full"
      style={{ background: "#131313", border: "1px solid #484847" }}
    >
      {/* Header */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
        <div className="flex flex-col gap-1">
          <h3 className="font-manrope font-extrabold text-sm uppercase tracking-tight text-white">
            Face Detection
          </h3>
          <p className="font-jakarta font-bold text-[10px] uppercase tracking-widest" style={{ color: "#ADAAAA", letterSpacing: "1.2px" }}>
            Visitor Classification Frequency
          </p>
        </div>

        {/* Legend */}
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-sm" style={{ background: "#FDD34D" }} />
            <span className="font-jakarta font-bold text-[10px] uppercase tracking-widest" style={{ color: "#ADAAAA" }}>
              Family
            </span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-sm" style={{ background: "#F5D1FB" }} />
            <span className="font-jakarta font-bold text-[10px] uppercase tracking-widest" style={{ color: "#ADAAAA" }}>
              Unknown
            </span>
          </div>
        </div>
      </div>

      {/* Chart */}
      <div className="w-full overflow-x-auto">
        <div className="min-w-[500px] h-48 relative flex items-end justify-between px-4 pb-8">
          {/* Day labels at the bottom */}
          {days.map((day, i) => (
            <div key={day} className="flex flex-col items-center flex-1">
              <div className="flex items-end gap-1 mb-2">
                {/* Family bar */}
                <div
                  className="w-10 rounded-sm transition-all duration-500 hover:brightness-110"
                  style={{
                    height: `${data[i].family * 1.5}px`,
                    background: "#FDD34D",
                  }}
                />
                {/* Unknown bar */}
                <div
                  className="w-10 rounded-sm transition-all duration-500 hover:brightness-110"
                  style={{
                    height: `${data[i].unknown * 1.5}px`,
                    background: "#F5D1FB",
                  }}
                />
              </div>
              <span className="font-jakarta font-bold text-[8px] uppercase tracking-tight" style={{ color: "#ADAAAA" }}>
                {day}
              </span>
            </div>
          ))}

          {/* Background grid line (bottom) */}
          <div className="absolute bottom-6 left-0 right-0 h-[1px] bg-[#484847]" />
        </div>
      </div>
    </div>
  );
}
